/// <summary>
/// Extension of the <c>PurchAgreementHeader</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tablestr(PurchAgreementHeader))]
final class PurchAgreementHeaderETGSPAIN_Extension
{    
}

Method.Source:
/// <summary>
/// Initializes the table data from the Operations table.
/// </summary>
/// <param name="_ETGSPAINPurchOperationTable">ETGSPAINPurchOperationTable.</param>
void initFromETGSPAINPurchOperationTable(ETGSPAINPurchOperationTable _ETGSPAINPurchOperationTable)
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.ETGSPAINAgreementOperationId = _ETGSPAINPurchOperationTable.OperationId;
    }
}

/// <summary>
/// Finds the specific record in the <c>PurchAgreementHeader</c> table using its Operation ID.
/// </summary>
/// <param name="_ETGSPAINOperationId">
/// The <c>ETGSPAINPurchOperationId</c> ID of the record to find.
/// </param>
/// <param name="_forUpdate">
/// A <c>Boolean</c> value indicating whether the record is for reading or writing; optional.
/// </param>
/// <returns>
/// A record from the <c>PurchAgreementHeader</c> table; otherwise, an empty record.
/// </returns>
static PurchAgreementHeader ETGSPAINfindETGSPAINOperationId(ETGSPAINPurchOperationId   _ETGSPAINPurchOperationId,
                                                    boolean             _forUpdate = false)
{
    PurchAgreementHeader    purchAgreementHeader;
    CompanyInfo             companyInfo;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (_ETGSPAINPurchOperationId)
        {
            if (_forUpdate)
            {
                purchAgreementHeader.selectForUpdate(_forUpdate);
            }

            select firstonly purchAgreementHeader
            where purchAgreementHeader.ETGSPAINAgreementOperationId  == _ETGSPAINPurchOperationId
            exists join companyInfo
                where companyInfo.RecId                         == purchAgreementHeader.BuyingLegalEntity
                    && companyInfo.DataArea                     == curext();
        }
    }

    return purchAgreementHeader;
}

/// <summary>
/// Method to change the <c>Mandatory</c> property of certain fields when agreements use Operations.
/// </summary>
/// <remarks>It is important that some fields are mandatory when creating agreements that use Operations.</remarks>
public static void ETGSPAINmandatoryOperationFields(FormRun _formRun)
{
    PurchAgreementHeader    purchAgreementHeader    = _formRun.dataSource().cursor() as PurchAgreementHeader;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        _formRun.dataSource().object(fieldNum(PurchAgreementHeader, DefaultAgreementLineExpirationDate)).mandatory((purchAgreementHeader.ETGSPAINAgreementOperationId != ""));
    }
}
